import xml.etree.ElementTree as ET

def parse_xml(file):
    tree = ET.parse(file)
    root = tree.getroot()
    
    def recursive(node):
        if len(node) == 0:
            return node.text
        return {child.tag: recursive(child) for child in node}
        
    return recursive(root)